  "66": { fr: "Garde offensive", en: "Offensive Guard", max: 3, cat: 'def', description: { fr: "Accroît temporairement la puissance d'attaque après une garde parfaitement synchronisée.", en: "Temporarily increases attack power after executing a perfectly-timed guard." }, ranks: [{ fr: "Attaque +5 % lorsqu'il est actif.", en: "Attack +5% while active." }, { fr: "Attaque +10 % lorsqu'il est actif.", en: "Attack +10% while active." }, { fr: "Attaque +15 % lorsqu'il est actif.", en: "Attack +15% while active." }] },
  "67": { fr: "Embuscade", en: "Ambush", max: 3, cat: 'atk', description: { fr: "Augmente temporairement les dégâts infligés aux grands monstres par les attaques furtives.", en: "Temporarily increases damage to large monsters with a successful Sneak Attack." }, ranks: [{ fr: "Attaque +5 % lorsqu'il est actif.", en: "Attack +5% while active." }, { fr: "Attaque +10 % lorsqu'il est actif.", en: "Attack +10% while active." }, { fr: "Attaque +15 % lorsqu'il est actif.", en: "Attack +15% while active." }] },
  "68": { fr: "Attaque perfide", en: "Critical Status", max: 3, cat: 'atk', description: { fr: "Augmente les afflictions (paralysie, poison, sommeil, explosion) infligées par des coups critiques.", en: "Increases abnormal status effects (paralysis, poison, sleep, blast) when landing critical hits." }, ranks: [{ fr: "Augmente légèrement les afflictions infligées par des coups critiques.", en: "Slightly increases abnormal status effects when landing critical hits." }, { fr: "Augmente les afflictions infligées par des coups critiques.", en: "Increases abnormal status effects when landing critical hits." }, { fr: "Augmente grandement les afflictions infligées par des coups critiques.", en: "Greatly increases abnormal status effects when landing critical hits." }] },
