  "70": { fr: "Puissance du Doshaguma", en: "Doshaguma's Might", max: 2, cat: 'util', ranks: [{ fr: "Octroie temporairement Attaque +10 après une Neutralisation ou un Duel de force réussi.", en: "Temporarily grants attack +10 after a successful Power Clash or Offset attack" }, { fr: "Octroie temporairement Attaque +25 après une Neutralisation ou un Duel de force réussi.", en: "Temporarily grants attack +25 after a successful Power Clash or Offset attack" }] },
  "71": { fr: "Éclat du Rathalos", en: "Rathalos's Flare", max: 2, cat: 'util', ranks: [{ fr: "Chances d'infliger des dégâts de feu supplémentaires après une attaque réussie.", en: "Chance to deal additional fire damage after landing an attack." }, { fr: "Augmente les dégâts de feu supplémentaires après une attaque réussie.", en: "Increases additional fire damage after landing an attack." }] },
  "72": { fr: "Machine de guerre", en: "Attack Boost", max: 5, cat: 'atk', description: { fr: "Augmente l'attaque.", en: "Increases attack power." }, ranks: [{ fr: "Attaque +3", en: "Attack +3" }, { fr: "Attaque +5", en: "Attack +5" }, { fr: "Attaque +7", en: "Attack +7" }, { fr: "Attaque +2 % Attaque +8", en: "Attack +2% Bonus: +8" }, { fr: "Attaque +4 % Attaque +9", en: "Attack +4% Bonus: +9" }] },
  "73": { fr: "Faveur de la gloire", en: "Glory's Favor", max: 1, cat: 'util', ranks: [{ fr: "Permet d'obtenir plus de récompenses cible. (Hors quête rejointe en cours de route.)", en: "Increases quest target rewards. (No effect when joining mid-quest.)" }] },
  "74": { fr: "Esprit du festival", en: "Festival Spirit", max: 1, cat: 'util', ranks: [{ fr: "Permet de dépecer les monstres une fois de plus lors des quêtes. (Hors quête rejointe en cours de route.)", en: "Lets you carve one additional time from carcasses during quests. (No effect when joining mid-quest.)" }] },
  "75": { fr: "Incursion", en: "Foray", max: 5, cat: 'atk', description: { fr: "Augmente l'attaque et l'affinité contre les grands monstres empoisonnés ou paralysés.", en: "Increases attack power and affinity against large monsters affected by poison or paralysis." }, ranks: [{ fr: "Attaque +6 contre les grands monstres empoisonnés ou paralysés.", en: "Attack +6 against large monsters affected by poison or paralysis." }, { fr: "Attaque +8 et affinité +5 % contre les grands monstres empoisonnés ou paralysés.", en: "Attack +8 and affinity +5% against large monsters affected by poison or paralysis." }, { fr: "Attaque +10 et affinité +10 % contre les grands monstres empoisonnés ou paralysés.", en: "Attack +10 and affinity +10% against large monsters affected by poison or paralysis." }, { fr: "Attaque +12 et affinité +15 % contre les grands monstres empoisonnés ou paralysés.", en: "Attack +12 and affinity +15% against large monsters affected by poison or paralysis." }, { fr: "Attaque +15 et affinité +20 % contre les grands monstres empoisonnés ou paralysés.", en: "Attack +15 and affinity +20% against large monsters affected by poison or paralysis." }] },
  "76": { fr: "Acrobate", en: "Jump Master", max: 1, cat: 'util', description: { fr: "Empêche les attaques de vous repousser pendant un saut.", en: "Prevents attacks from knocking you back during a jump." }, ranks: [{ fr: "Annule les repoussements durant les sauts.", en: "Negates knockback during jumps." }] },
  "77": { fr: "Fenêtre d'invulnérabilité", en: "Evade Window", max: 5, cat: 'util', description: { fr: "Augmente la durée de l'invulnérabilité en cas d'esquive.", en: "Extends the invulnerability period when evading." }, ranks: [{ fr: "Augmente très légèrement la fenêtre d'invulnérabilité.", en: "Very slightly increases invulnerability window." }, { fr: "Augmente légèrement la fenêtre d'invulnérabilité.", en: "Slightly increases invulnerability window." }, { fr: "Augmente la fenêtre d'invulnérabilité.", en: "Increases invulnerability window." }, { fr: "Augmente grandement la fenêtre d'invulnérabilité.", en: "Greatly increases invulnerability window." }, { fr: "Augmente énormément la fenêtre d'invulnérabilité.", en: "Massively increases invulnerability window." }] },
  "78": { fr: "La nuit porte conseil", en: "Sleep Attack", max: 3, cat: 'atk', description: { fr: "Augmente la puissance des afflictions de type sommeil. Il y a une limite aux augmentations.", en: "Increases the rate of sleep buildup. (Sleep buildup has a maximum limit.)" }, ranks: [{ fr: "Accumulation sommeil +5 % Accumulation sommeil +10", en: "Sleep buildup +5% Bonus: +10" }, { fr: "Accumulation sommeil +10 % Accumulation sommeil +20", en: "Sleep buildup +10% Bonus: +20" }, { fr: "Accumulation sommeil +20 % Accumulation sommeil +50", en: "Sleep buildup +20% Bonus: +50" }] },
