  "80": { fr: "Bouchon d'oreilles", en: "Earplugs", max: 3, cat: 'def', description: { fr: "Confère une résistance aux rugissements des grands monstres.", en: "Grants protection from large monsters' roars." }, ranks: [{ fr: "Réduit les effets des petits rugissements.", en: "Reduces the effects of weak monster roars." }, { fr: "Annule les petits rugissements et réduit les effets des grands rugissements.", en: "Nullifies weak monster roars and reduces the effects of strong monster roars." }, { fr: "Annule les petits et grands rugissements.", en: "Nullifies weak and strong monster roars." }] },
  "81": { fr: "Contre-attaque", en: "Counterstrike", max: 3, cat: 'atk', description: { fr: "Accroît temporairement la puissance d'attaque après avoir été projeté.", en: "Temporarily increases attack power after being knocked back." }, ranks: [{ fr: "Attaque +10 lorsqu'il est actif.", en: "Attack +10 while active." }, { fr: "Attaque +15 lorsqu'il est actif. Augmente modérément la durée de l'effet.", en: "Attack +15 while active. Moderately extends effect time." }, { fr: "Attaque +25 lorsqu'il est actif. Augmente la durée de l'effet.", en: "Attack +25 while active. Extends effect time." }] },
