  "83": { fr: "Surcharge", en: "Charge Up", max: 1, cat: 'atk', description: { fr: "Augmente les dégâts et la puissance de l'étourdissement des attaques de marteau chargées.", en: "Increases the damage and stun power of charged hammer attacks." }, ranks: [{ fr: "Active l'effet.", en: "Activates skill effect." }] },
  "84": { fr: "Étanchéité", en: "Water Resistance", max: 3, cat: 'def', description: { fr: "Augmente la protection contre les attaques élémentaires eau puis les attaques physiques.", en: "Increases water resistance. Also improves defense at higher levels." }, ranks: [{ fr: "Résistance Eau +6", en: "Water resistance +6" }, { fr: "Résistance Eau +12", en: "Water resistance +12" }, { fr: "Résistance Eau +20 Défense +10", en: "Water resistance +20 Defense +10" }] },
  "85": { fr: "Matraquage", en: "Bludgeoner", max: 3, cat: 'atk', description: { fr: "Augmente les dégâts infligés quand votre arme est émoussée.", en: "Increases damage dealt when your weapon sharpness is low." }, ranks: [{ fr: "Dégâts +5 % lorsque la jauge de tranchant est dans le jaune ou moins.", en: "+5% damage dealt when your sharpness gauge is yellow or lower." }, { fr: "Dégâts +10 % lorsque la jauge de tranchant est dans le jaune ou moins.", en: "+10% damage dealt when your sharpness gauge is yellow or lower." }, { fr: "Dégâts +10 % lorsque la jauge de tranchant est dans le vert ou moins.", en: "+10% damage dealt when your sharpness gauge is green or lower." }] },
  "86": { fr: "Mort venue d'en haut", en: "Airborne", max: 1, cat: 'atk', description: { fr: "Augmente la puissance des attaques sautées.", en: "Increases the damage caused by jumping attacks." }, ranks: [{ fr: "Attaques sautées +10 %", en: "Jumping attack power +10%" }] },
