  "88": { fr: "Adaptabilité", en: "Adaptability", max: 2, cat: 'def', description: { fr: "Confère une résistance aux dégâts environnementaux, comme la chaleur ou le froid.", en: "Grants protection against environmental damage, such as from heat or cold." }, ranks: [{ fr: "Annule les effets du froid et de la chaleur.", en: "Negates the effects of heat and cold." }, { fr: "Annule les dégâts environnementaux.", en: "Negates environmental damage." }] },
  "89": { fr: "Douceur du cuir", en: "Buttery Leathercraft", max: 1, cat: 'util', ranks: [{ fr: "Augmente temporairement votre affinité pendant les glissades.", en: "Increases your affinity temporarily when sliding on terrain." }] },
